const express = require('express');
const bodyParser = require('body-parser');

const app = express();
const PORT = process.env.PORT || 3000;

app.use(bodyParser.json());

// In-memory data store for demonstration purposes.
// In a real application, this would be replaced with a persistent database.
const users = {
    // Example user 'player123'
    'player123': {
        levelsCompleted: {}, // Stores best score/time for each level: { levelId: { score: number, time: number, completedAt: Date } }
        rewards: {
            coins: 0,
            gems: 0
        }
    }
};

/**
 * Calculates rewards based on level completion metrics.
 * This is a simplified example; a real game would have more complex logic,
 * potentially driven by server-side level configurations.
 * @param {string} levelId The ID of the completed level.
 * @param {number} score The player's score for the level.
 * @param {number} time The player's time to complete the level in seconds.
 * @returns {object} An object containing the awarded coins and gems.
 */
function calculateRewards(levelId, score, time) {
    let coins = 50; // Base coins for completing any level
    let gems = 0;   // Base gems

    // Score-based bonus
    coins += Math.floor(score / 100); // 1 coin for every 100 points
    if (score >= 1000) {
        gems += 1; // Award an extra gem for scores 1000 or higher
    }

    // Time-based bonus (faster times get more bonus)
    // Assuming typical level times are between 30 and 300 seconds.
    if (time > 0 && time < 300) {
        coins += Math.floor((300 - time) / 5); // Faster completion gives more coins
    } else if (time <= 0) { // Very fast or invalid time, award max bonus for time
        coins += 60;
    }

    // Example for specific level rewards
    if (levelId === 'tutorial_001') {
        gems += 1; // First level might give an extra gem
    }

    return {
        coins: Math.max(0, coins), // Ensure no negative rewards
        gems: Math.max(0, gems)
    };
}

/**
 * @api {post} /levels/complete Complete a Level
 * @apiName CompleteLevel
 * @apiGroup Levels
 * @apiHeader {String} X-User-Id Player's unique ID.
 * @apiParam {String} levelId Unique identifier for the completed level (e.g., "puzzle_001").
 * @apiParam {Number} score Player's score for the level.
 * @apiParam {Number} time Player's time taken to complete the level in seconds.
 * @apiSuccess {String} message A success message.
 * @apiSuccess {Object} awardedRewards Object containing coins and gems awarded for this completion.
 * @apiSuccess {Object} playerTotalRewards Object containing the player's current total rewards.
 * @apiError (400 Bad Request) {String} message Error message for invalid input.
 * @apiError (401 Unauthorized) {String} message Error message for invalid or missing User ID.
 */
app.post('/levels/complete', (req, res) => {
    const userId = req.headers['x-user-id'];
    if (!userId || !users[userId]) {
        return res.status(401).json({ message: 'Unauthorized: Invalid or missing User ID. Please provide X-User-Id header.' });
    }

    const { levelId, score, time } = req.body;

    // Input Validation
    if (!levelId || typeof levelId !== 'string') {
        return res.status(400).json({ message: 'levelId is required and must be a string.' });
    }
    if (typeof score !== 'number' || score < 0) {
        return res.status(400).json({ message: 'score is required and must be a non-negative number.' });
    }
    if (typeof time !== 'number' || time <= 0) {
        return res.status(400).json({ message: 'time is required and must be a positive number (in seconds).' });
    }

    // Determine if this is a new best score/time for the level
    const currentBest = users[userId].levelsCompleted[levelId];
    const newCompletion = { score, time, completedAt: new Date() };

    let isNewBestScore = !currentBest || score > currentBest.score;
    // In casual games, sometimes any completion awards rewards, sometimes only new bests.
    // For this example, we'll award rewards every time, but only update best score if higher.
    if (isNewBestScore) {
        users[userId].levelsCompleted[levelId] = newCompletion;
        console.log(`User ${userId}: New best completion for level ${levelId} - Score: ${score}, Time: ${time}`);
    } else {
        console.log(`User ${userId}: Re-completed level ${levelId} - Score: ${score}, Time: ${time}. Best score remains ${currentBest.score}.`);
    }

    // Calculate and award rewards based on client-reported metrics
    const awardedRewards = calculateRewards(levelId, score, time);

    users[userId].rewards.coins += awardedRewards.coins;
    users[userId].rewards.gems += awardedRewards.gems;

    console.log(`User ${userId} awarded ${awardedRewards.coins} coins and ${awardedRewards.gems} gems.`);
    console.log(`User ${userId} total rewards: Coins: ${users[userId].rewards.coins}, Gems: ${users[userId].rewards.gems}`);

    res.status(200).json({
        message: 'Level completed successfully and rewards claimed!',
        awardedRewards: awardedRewards,
        playerTotalRewards: users[userId].rewards
    });
});

/**
 * @api {get} /player/rewards Get Player's Current Rewards
 * @apiName GetPlayerRewards
 * @apiGroup Player
 * @apiHeader {String} X-User-Id Player's unique ID.
 * @apiSuccess {Object} rewards Object containing the player's current total coins and gems.
 * @apiSuccess {Number} rewards.coins Total number of coins.
 * @apiSuccess {Number} rewards.gems Total number of gems.
 * @apiError (401 Unauthorized) {String} message Error message for invalid or missing User ID.
 */
app.get('/player/rewards', (req, res) => {
    const userId = req.headers['x-user-id'];
    if (!userId || !users[userId]) {
        return res.status(401).json({ message: 'Unauthorized: Invalid or missing User ID. Please provide X-User-Id header.' });
    }

    res.status(200).json({
        rewards: users[userId].rewards
    });
});

app.listen(PORT, () => {
    console.log(`Mobile Game API server running on port ${PORT}`);
    console.log('\n--- Test Endpoints ---');
    console.log('1. Complete a level:');
    console.log(`   curl -X POST -H "Content-Type: application/json" -H "X-User-Id: player123" -d '{"levelId": "puzzle_001", "score": 1250, "time": 90}' http://localhost:${PORT}/levels/complete`);
    console.log(`   curl -X POST -H "Content-Type: application/json" -H "X-User-Id: player123" -d '{"levelId": "tutorial_001", "score": 800, "time": 120}' http://localhost:${PORT}/levels/complete`);
    console.log('\n2. Get player rewards:');
    console.log(`   curl -X GET -H "X-User-Id: player123" http://localhost:${PORT}/player/rewards`);
    console.log('\n3. Test with a different user (e.g., "player456" - will fail due to no such user):');
    console.log(`   curl -X GET -H "X-User-Id: player456" http://localhost:${PORT}/player/rewards`);
});